#include<bits/stdc++.h>
using namespace std;
const int maxn=1e5+4;
vector<int> a[maxn];
int mark[maxn];
deque<int> b;
void dfs(int n){
    cout<<n<<' ';
    mark[n]=1;
    for(int i=0;i<a[n].size();i++){
        if(!mark[a[n][i]])dfs(a[n][i]);
    }
}
void bfs(){
    b.push_back(1);
    mark[1]=1;
    while(!b.empty()){
        int u=b.front();
        b.pop_front();
        cout<<u<<' ';
        for(int i=0;i<a[u].size();i++){
            int v=a[u][i];
            if(!mark[v]){
                b.push_back(v);
                mark[v]=1;
            }
        }
    }
}
int main(){
    int n,m;
    cin>>n>>m;
    for(int i=0;i<m;i++){
        int u,v;
        cin>>u>>v;
        a[u].push_back(v);
    }
	//sort(a[1].begin(),a[1].end());
    //for(int i=1;i<=a[1].size();i++)cout<<a[1][i-1]<<' ';
    //cout<<endl;
	//cout<<"OK"<<endl;
	for(int i=1;i<=n;i++)sort(a[i].begin(),a[i].end());
    dfs(1);
    cout<<endl;
    memset(mark,0,sizeof(mark));
    bfs();
    return 0;
}
